     1→/**
     2→ * MMS Store
     3→ *
     4→ * Central state management using @belt/tools machines.
     5→ * This replaces React hooks (useState, useEffect) and zustand per project constraints.
     6→ *
     7→ * @see specs/006-user-interface.md Section 6.4
     8→ * @see README.md for @belt/tools API reference
     9→ */
    10→
    11→import { createMachine } from '@belt/tools';
    12→
    13→import {
    14→  fleetSlice,
    15→  fleetAsyncSlice,
    16→  canvasSlice,
    17→  canvasDataSlice,
    18→  pmSlice,
    19→  pmAsyncSlice,
    20→  scenarioSlice,
    21→  scenarioAsyncSlice,
    22→  uiSlice,
    23→  overlaySlice,
    24→} from './slices';
    25→
    26→// =============================================================================
    27→// MMS Application Machine
    28→// =============================================================================
    29→
    30→/**
    31→ * Main application state machine.
    32→ *
    33→ * Usage in React components:
    34→ * ```tsx
    35→ * function TrainList() {
    36→ *   const { state, actions } = mmsMachine.useMachine('fleet');
    37→ *   return (
    38→ *     <ul>
    39→ *       {state.trains.map(train => (
    40→ *         <li key={train.id} onClick={() => actions.selectTrain(train.id)}>
    41→ *           {train.trainNumber}
    42→ *         </li>
    43→ *       ))}
    44→ *     </ul>
    45→ *   );
    46→ * }
    47→ * ```
    48→ */
    49→export const mmsMachine = createMachine({
    50→  id: 'mms',
    51→  slices: {
    52→    fleet: fleetSlice,
    53→    fleetApi: fleetAsyncSlice,
    54→    canvas: canvasSlice,
    55→    canvasData: canvasDataSlice,
    56→    pm: pmSlice,
    57→    pmApi: pmAsyncSlice,
    58→    scenario: scenarioSlice,
    59→    scenarioApi: scenarioAsyncSlice,
    60→    ui: uiSlice,
    61→    overlay: overlaySlice,
    62→  },
    63→  context: {
    64→    // User ID for private cache policy
    65→    userID: null as string | null,
    66→    // Context properties for async slices
    67→    baseUrl: '/api/v1',
    68→    startDate: new Date().toISOString().split('T')[0],
    69→    endDate: new Date(Date.now() + 84 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    70→  },
    71→});
    72→
    73→// =============================================================================
    74→// Type Exports
    75→// =============================================================================
    76→
    77→export type MmsMachine = typeof mmsMachine;
    78→export type MmsSliceId = keyof typeof mmsMachine extends infer K
    79→  ? K extends 'useMachine' | 'useSlice' | 'dispatch' | 'getState' | 'subscribe'
    80→    ? never
    81→    : K
    82→  : never;
    83→
    84→// =============================================================================
    85→// Re-exports
    86→// =============================================================================
    87→
    88→// Types
    89→export * from './types';
    90→
    91→// Slices
    92→export * from './slices';
    93→
    94→// Batch utilities
    95→export {
    96→  batchDispatch,
    97→  batchDispatches,
    98→  flushBatch,
    99→  cancelBatch,
   100→  getBatchStatus,
   101→  createBatchedDispatcher,
   102→  debouncedBatchDispatch,
   103→  throttledBatchDispatch,
   104→  createPointerMoveHandler,
   105→  createWheelHandler,
   106→} from './utils/batch';
   107→
   108→// =============================================================================
   109→// Convenience Hooks
   110→// =============================================================================
   111→
   112→/**
   113→ * Hook for fleet state and actions
   114→ *
   115→ * @example
   116→ * ```tsx
   117→ * function FleetView() {
   118→ *   const { state, actions } = useFleet();
   119→ *   return <div>{state.trains.length} trains</div>;
   120→ * }
   121→ * ```
   122→ */
   123→export function useFleet() {
   124→  return mmsMachine.useMachine('fleet');
   125→}
   126→
   127→/**
   128→ * Hook for canvas state and actions
   129→ *
   130→ * @example
   131→ * ```tsx
   132→ * function Canvas() {
   133→ *   const { state, actions } = useCanvas();
   134→ *   return <div>Zoom: {state.zoom}</div>;
   135→ * }
   136→ * ```
   137→ */
   138→export function useCanvas() {
   139→  return mmsMachine.useMachine('canvas');
   140→}
   141→
   142→/**
   143→ * Hook for canvas data (strategic/tactical views)
   144→ *
   145→ * @example
   146→ * ```tsx
   147→ * function StrategicView() {
   148→ *   const { state, actions } = useCanvasData();
   149→ *   if (state.strategicLoading) return <Spinner />;
   150→ *   return <Heatmap data={state.strategicData} />;
   151→ * }
   152→ * ```
   153→ */
   154→export function useCanvasData() {
   155→  return mmsMachine.useMachine('canvasData');
   156→}
   157→
   158→/**
   159→ * Hook for PM schedule state and actions
   160→ *
   161→ * @example
   162→ * ```tsx
   163→ * function PmSchedule() {
   164→ *   const { state, actions } = usePm();
   165→ *   return <div>{state.pmSchedule.length} PMs</div>;
   166→ * }
   167→ * ```
   168→ */
   169→export function usePm() {
   170→  return mmsMachine.useMachine('pm');
   171→}
   172→
   173→/**
   174→ * Hook for scenario state and actions
   175→ *
   176→ * @example
   177→ * ```tsx
   178→ * function ScenarioPanel() {
   179→ *   const { state, actions } = useScenario();
   180→ *   return <div>{state.scenarios.length} scenarios</div>;
   181→ * }
   182→ * ```
   183→ */
   184→export function useScenario() {
   185→  return mmsMachine.useMachine('scenario');
   186→}
   187→
   188→/**
   189→ * Hook for UI state and actions
   190→ *
   191→ * @example
   192→ * ```tsx
   193→ * function ToastContainer() {
   194→ *   const { state, actions } = useUi();
   195→ *   return (
   196→ *     <div>
   197→ *       {state.toasts.map(toast => (
   198→ *         <Toast key={toast.id} {...toast} onDismiss={() => actions.removeToast(toast.id)} />
   199→ *       ))}
   200→ *     </div>
   201→ *   );
   202→ * }
   203→ * ```
   204→ */
   205→export function useUi() {
   206→  return mmsMachine.useMachine('ui');
   207→}
   208→
   209→/**
   210→ * Hook for overlay state and actions (manhour, drift)
   211→ *
   212→ * @example
   213→ * ```tsx
   214→ * function OverlayPanel() {
   215→ *   const { state, actions } = useOverlay();
   216→ *   return (
   217→ *     <div>
   218→ *       {state.manhourData && <ManHourChart data={state.manhourData} />}
   219→ *       {state.driftData && <DriftList data={state.driftData} />}
   220→ *     </div>
   221→ *   );
   222→ * }
   223→ * ```
   224→ */
   225→export function useOverlay() {
   226→  return mmsMachine.useMachine('overlay');
   227→}
   228→
   229→// =============================================================================
   230→// Async Data Hooks
   231→// =============================================================================
   232→
   233→/**
   234→ * Hook for async fleet data loading
   235→ *
   236→ * @example
   237→ * ```tsx
   238→ * function FleetLoader() {
   239→ *   const { data, loading, error, refetch } = useFleetApi();
   240→ *
   241→ *   if (loading) return <Spinner />;
   242→ *   if (error) return <Error message={error.message} />;
   243→ *
   244→ *   return <FleetView data={data} />;
   245→ * }
   246→ * ```
   247→ */
   248→export function useFleetApi() {
   249→  return mmsMachine.useMachine('fleetApi');
   250→}
   251→
   252→/**
   253→ * Hook for async PM data loading
   254→ */
   255→export function usePmApi() {
   256→  return mmsMachine.useMachine('pmApi');
   257→}
   258→
   259→/**
   260→ * Hook for async scenario data loading
   261→ */
   262→export function useScenarioApi() {
   263→  return mmsMachine.useMachine('scenarioApi');
   264→}
   265→

