   505→    setManhourError: (error: string) => void;
   506→  },
   507→  options: { baseUrl?: string; weeks?: number; depotId?: string } = {}
   508→): Promise<void> {
   509→  const { baseUrl = '/api/v1', weeks = 12, depotId } = options;
   510→
   511→  dispatch.setManhourLoading(true);
   512→
   513→  const params = new URLSearchParams();
   514→  params.set('weeks', String(weeks));
   515→  if (depotId) {
   516→    params.set('depotId', depotId);
   517→  }
   518→
   519→  try {
   520→    const response = await fetch(`${baseUrl}/canvas/manhour-overlay?${params}`);
   521→
   522→    if (!response.ok) {
   523→      throw new Error(`Failed to fetch man-hour overlay: ${response.status}`);
   524→    }
   525→
   526→    const json = await response.json() as { data: ManhourOverlayData };
   527→    dispatch.setManhourData(json.data);
   528→  } catch (error) {
   529→    const message = error instanceof Error ? error.message : 'Unknown error';
   530→    dispatch.setManhourError(message);
   531→  }
   532→}
   533→
   534→/**
   535→ * Load drift overlay data from API
   536→ */
   537→export async function loadDriftOverlayData(
   538→  dispatch: {
   539→    setDriftLoading: (loading: boolean) => void;
   540→    setDriftData: (data: DriftOverlayData) => void;
   541→    setDriftError: (error: string) => void;
   542→  },
   543→  options: { baseUrl?: string; baselineId?: string } = {}
   544→): Promise<void> {
   545→  const { baseUrl = '/api/v1', baselineId } = options;
   546→
   547→  dispatch.setDriftLoading(true);
   548→
   549→  const params = new URLSearchParams();
   550→  if (baselineId) {
   551→    params.set('baselineId', baselineId);
   552→  }
   553→
   554→  try {
   555→    const response = await fetch(`${baseUrl}/canvas/drift-overlay?${params}`);
   556→
   557→    if (!response.ok) {
   558→      throw new Error(`Failed to fetch drift overlay: ${response.status}`);
   559→    }
   560→
   561→    const json = await response.json() as { data: DriftOverlayData };
   562→    dispatch.setDriftData(json.data);
   563→  } catch (error) {
   564→    const message = error instanceof Error ? error.message : 'Unknown error';
   565→    dispatch.setDriftError(message);
   566→  }
   567→}
   568→
   569→// =============================================================================
   570→// Selectors
   571→// =============================================================================
   572→
   573→/**
   574→ * Get filtered man-hour weeks based on depot filter
   575→ */
   576→export function selectFilteredManhourWeeks(state: OverlaySliceState): ManhourWeekData[] {
   577→  if (!state.manhourData) return [];
   578→
   579→  if (!state.manhourDepotFilter) {
   580→    return state.manhourData.weeks;
   581→  }
   582→
   583→  return state.manhourData.weeks.map(week => ({
   584→    ...week,
   585→    depots: week.depots.filter(d => d.depotId === state.manhourDepotFilter),
   586→  }));
   587→}
   588→
   589→/**
   590→ * Get weeks with overloaded status
   591→ */
   592→export function selectOverloadedWeeks(state: OverlaySliceState): ManhourWeekData[] {
   593→  if (!state.manhourData) return [];
   594→
   595→  return state.manhourData.weeks.filter(week =>
   596→    week.depots.some(d => d.status === 'OVERLOADED')
   597→  );
   598→}
   599→
   600→/**
   601→ * Get total overloaded hours across all weeks
   602→ */
   603→export function selectTotalOverloadedHours(state: OverlaySliceState): number {
   604→  if (!state.manhourData) return 0;
   605→
   606→  return state.manhourData.weeks.reduce((total, week) => {
   607→    return total + week.depots.reduce((weekTotal, depot) => {
   608→      if (depot.status === 'OVERLOADED') {
   609→        return weekTotal + (depot.requiredHours - depot.availableHours);
   610→      }
   611→      return weekTotal;
   612→    }, 0);
   613→  }, 0);
   614→}
   615→
   616→/**
   617→ * Get filtered trains based on drift severity filter
   618→ */
   619→export function selectFilteredDriftTrains(state: OverlaySliceState): TrainDriftData[] {
   620→  if (!state.driftData) return [];
   621→
   622→  if (!state.driftSeverityFilter) {
   623→    return state.driftData.trains;
   624→  }
   625→
   626→  return state.driftData.trains.filter(t => t.driftSeverity === state.driftSeverityFilter);
   627→}
   628→
   629→/**
   630→ * Get trains requiring replan (RED severity)
   631→ */
   632→export function selectTrainsRequiringReplan(state: OverlaySliceState): TrainDriftData[] {
   633→  if (!state.driftData) return [];
   634→  return state.driftData.trains.filter(t => t.driftSeverity === 'RED');
   635→}
   636→
   637→/**
   638→ * Get drift summary statistics
   639→ */
   640→export function selectDriftSummaryStats(state: OverlaySliceState): {
   641→  totalTrains: number;
   642→  greenCount: number;
   643→  yellowCount: number;
   644→  redCount: number;
   645→} {
   646→  if (!state.driftData) {
   647→    return { totalTrains: 0, greenCount: 0, yellowCount: 0, redCount: 0 };
   648→  }
   649→
   650→  const trains = state.driftData.trains;
   651→  return {
   652→    totalTrains: trains.length,
   653→    greenCount: trains.filter(t => t.driftSeverity === 'GREEN').length,
   654→    yellowCount: trains.filter(t => t.driftSeverity === 'YELLOW').length,
   655→    redCount: trains.filter(t => t.driftSeverity === 'RED').length,
   656→  };
   657→}
   658→
   659→/**
   660→ * Check if man-hour data is stale (>5 minutes)
   661→ */
   662→export function isManhourDataStale(state: OverlaySliceState): boolean {
   663→  if (!state.manhourLastFetch) return true;
   664→  return Date.now() - state.manhourLastFetch > 5 * 60 * 1000;
   665→}
   666→
   667→/**
   668→ * Check if drift data is stale (>5 minutes)
   669→ */
   670→export function isDriftDataStale(state: OverlaySliceState): boolean {
   671→  if (!state.driftLastFetch) return true;
   672→  return Date.now() - state.driftLastFetch > 5 * 60 * 1000;
   673→}
   674→
   675→/**
   676→ * Load baseline shadow overlay data from API
   677→ */
   678→export async function loadBaselineShadowData(
   679→  dispatch: {
   680→    setBaselineShadowLoading: (loading: boolean) => void;
   681→    setBaselineShadowData: (data: BaselineShadowData) => void;
   682→    setBaselineShadowError: (error: string) => void;
   683→  },
   684→  options: {
   685→    baseUrl?: string;
   686→    baselineId?: string;
   687→    fromDate?: string;
   688→    toDate?: string;
   689→    trainIds?: string[];
   690→  } = {}
   691→): Promise<void> {
   692→  const { baseUrl = '/api/v1', baselineId, fromDate, toDate, trainIds } = options;
   693→
   694→  dispatch.setBaselineShadowLoading(true);
   695→
   696→  const params = new URLSearchParams();
   697→  if (baselineId) {
   698→    params.set('baselineId', baselineId);
   699→  }
   700→  if (fromDate) {
   701→    params.set('fromDate', fromDate);
   702→  }
   703→  if (toDate) {
   704→    params.set('toDate', toDate);
   705→  }
   706→  if (trainIds && trainIds.length > 0) {
   707→    params.set('trainIds', trainIds.join(','));
   708→  }
   709→
   710→  try {
   711→    const response = await fetch(`${baseUrl}/canvas/baseline-shadow?${params}`);
   712→
   713→    if (!response.ok) {
   714→      throw new Error(`Failed to fetch baseline shadow: ${response.status}`);
   715→    }
   716→
   717→    const json = await response.json() as { data: BaselineShadowData };
   718→    dispatch.setBaselineShadowData(json.data);
   719→  } catch (error) {
   720→    const message = error instanceof Error ? error.message : 'Unknown error';
   721→    dispatch.setBaselineShadowError(message);
   722→  }
   723→}
   724→
   725→// =============================================================================
   726→// Baseline Shadow Selectors
   727→// =============================================================================
   728→
   729→/**
   730→ * Get filtered baseline PM blocks based on status filter
   731→ */
   732→export function selectFilteredBaselinePmBlocks(state: OverlaySliceState): BaselinePmBlock[] {
   733→  if (!state.baselineShadowData) return [];
   734→
   735→  if (!state.baselineShadowStatusFilter) {
   736→    return state.baselineShadowData.pmBlocks;
   737→  }
   738→
   739→  return state.baselineShadowData.pmBlocks.filter(
   740→    pm => pm.status === state.baselineShadowStatusFilter
   741→  );
   742→}
   743→
   744→/**
   745→ * Get PMs with significant drift (moved by more than N days)
   746→ */
   747→export function selectSignificantDriftPms(
   748→  state: OverlaySliceState,
   749→  thresholdDays: number = 7
   750→): BaselinePmBlock[] {
   751→  if (!state.baselineShadowData) return [];
   752→
   753→  return state.baselineShadowData.pmBlocks.filter(
   754→    pm => pm.status === 'MOVED' && Math.abs(pm.driftDays) > thresholdDays
   755→  );
   756→}
   757→
   758→/**
   759→ * Get baseline shadow summary statistics
   760→ */
   761→export function selectBaselineShadowSummary(state: OverlaySliceState): BaselineShadowData['summary'] | null {
   762→  return state.baselineShadowData?.summary ?? null;
   763→}
   764→
   765→/**
   766→ * Check if baseline shadow data is stale (>5 minutes)
   767→ */
   768→export function isBaselineShadowDataStale(state: OverlaySliceState): boolean {
   769→  if (!state.baselineShadowLastFetch) return true;
   770→  return Date.now() - state.baselineShadowLastFetch > 5 * 60 * 1000;
   771→}
   772→
   773→// =============================================================================
   774→// Bow-Wave Data Loading Functions
   775→// =============================================================================
   776→
   777→/**
   778→ * Load bow-wave analysis data from API
   779→ *
   780→ * This fetches strategic planner bow-wave risk analysis which shows
   781→ * maintenance clustering patterns over the planning horizon.
   782→ */
   783→export async function loadBowWaveOverlayData(
   784→  dispatch: {
   785→    setBowWaveLoading: (loading: boolean) => void;
   786→    setBowWaveData: (data: BowWaveOverlayData) => void;
   787→    setBowWaveError: (error: string) => void;
   788→  },
   789→  options: {
   790→    baseUrl?: string;
   791→    fleetId?: string;
   792→    planId?: string;
   793→  } = {}
   794→): Promise<void> {
   795→  const { baseUrl = '/api/v1', fleetId, planId } = options;
   796→
   797→  dispatch.setBowWaveLoading(true);
   798→
   799→  const params = new URLSearchParams();
   800→  if (fleetId) {
   801→    params.set('fleetId', fleetId);
   802→  }
   803→  if (planId) {
   804→    params.set('planId', planId);
   805→  }
   806→
   807→  try {
   808→    const response = await fetch(`${baseUrl}/canvas/bow-wave?${params}`);
   809→
   810→    if (!response.ok) {
   811→      throw new Error(`Failed to fetch bow-wave analysis: ${response.status}`);
   812→    }
   813→
   814→    const json = await response.json() as { data: BowWaveOverlayData };
   815→    dispatch.setBowWaveData(json.data);
   816→  } catch (error) {
   817→    const message = error instanceof Error ? error.message : 'Unknown error';
   818→    dispatch.setBowWaveError(message);
   819→  }
   820→}
   821→
   822→// =============================================================================
   823→// Bow-Wave Selectors
   824→// =============================================================================
   825→
   826→/**
   827→ * Get bow-wave risk level as display-friendly string
   828→ */
   829→export function selectBowWaveRiskDisplay(state: OverlaySliceState): {
   830→  level: BowWaveRiskLevel;
   831→  label: string;
   832→  color: 'green' | 'yellow' | 'orange' | 'red';
   833→} {
   834→  if (!state.bowWaveData) {
   835→    return { level: 'LOW', label: 'No Data', color: 'green' };
   836→  }
   837→
   838→  const colorMap: Record<BowWaveRiskLevel, 'green' | 'yellow' | 'orange' | 'red'> = {
   839→    LOW: 'green',
   840→    MEDIUM: 'yellow',
   841→    HIGH: 'orange',
   842→    CRITICAL: 'red',
   843→  };
   844→
   845→  const labelMap: Record<BowWaveRiskLevel, string> = {
   846→    LOW: 'Bow-Wave Risk: Low',
   847→    MEDIUM: 'Bow-Wave Risk: Medium',
   848→    HIGH: 'Bow-Wave Risk: High',
   849→    CRITICAL: 'Bow-Wave Risk: Critical',
   850→  };
   851→
   852→  return {
   853→    level: state.bowWaveData.riskLevel,
   854→    label: labelMap[state.bowWaveData.riskLevel],
   855→    color: colorMap[state.bowWaveData.riskLevel],
   856→  };
   857→}
   858→
   859→/**
   860→ * Get peak periods requiring attention
   861→ */
   862→export function selectBowWavePeakPeriods(state: OverlaySliceState): BowWavePeakPeriod[] {
   863→  if (!state.bowWaveData) return [];
   864→  return state.bowWaveData.peakPeriods;
   865→}
   866→
   867→/**
   868→ * Get high-priority recommendations
   869→ */
   870→export function selectBowWaveHighPriorityRecommendations(
   871→  state: OverlaySliceState
   872→): BowWaveRecommendation[] {
   873→  if (!state.bowWaveData) return [];
   874→  return state.bowWaveData.recommendations.filter(r => r.priority === 'HIGH');
   875→}
   876→
   877→/**
   878→ * Get quarterly load for selected quarter
   879→ */
   880→export function selectBowWaveSelectedQuarterLoad(
   881→  state: OverlaySliceState
   882→): QuarterlyLoad | null {
   883→  if (!state.bowWaveData || !state.bowWaveSelectedQuarter) return null;
   884→  return state.bowWaveData.quarterlyLoads.find(
   885→    q => q.quarter === state.bowWaveSelectedQuarter
   886→  ) ?? null;
   887→}
   888→
   889→/**
   890→ * Get summary statistics for bow-wave
   891→ */
   892→export function selectBowWaveSummary(state: OverlaySliceState): BowWaveOverlayData['summary'] | null {
   893→  return state.bowWaveData?.summary ?? null;
   894→}
   895→
   896→/**
   897→ * Check if bow-wave data is stale (>10 minutes for strategic data)
   898→ */
   899→export function isBowWaveDataStale(state: OverlaySliceState): boolean {
   900→  if (!state.bowWaveLastFetch) return true;
   901→  return Date.now() - state.bowWaveLastFetch > 10 * 60 * 1000;
   902→}
   903→
   904→/**
   905→ * Convert risk score (0-1) to risk level
   906→ */
   907→export function riskScoreToLevel(score: number): BowWaveRiskLevel {
   908→  if (score < 0.25) return 'LOW';
   909→  if (score < 0.5) return 'MEDIUM';
   910→  if (score < 0.75) return 'HIGH';
   911→  return 'CRITICAL';
   912→}
